// // This module implements a 3-input K-Nearest Neighbors (KNN) classifier that classifies the input based on the following criteria:
// - If the sum of the three inputs is greater than 3, the output should be classified as '0'.
// - If the sum is less than or equal to 1 but greater than 3, the output should be classified as '1'.
// - If the sum is less than or equal to 1, the output should be classified as '2'.
// The inputs are binary (0 or 1).
module knn_classifier (  
    input [2:0] data,  
    output reg [1:0] classification  
);  
    always @(*) begin  
        if (data[0] + data[1] + data[2] <= 1)  
            classification = 2'b00; // Class 0  
        else if (data[0] + data[1] + data[2] <= 3)  
            classification = 2'b01; // Class 1  
        else  
            classification = 2'b10; // Class 2  
    end  
endmodule

